#!/usr/bin/env python3
"""restore_repo_memory_v379.py — catch the repo's memory/ tracking up to v379.

Run on the DGX (repo root). Then review `git diff memory/` and commit + push.

  PRD.md / ROADMAP.md -> overwritten with the sandbox-current versions
                         (backup written to <file>.bak.premerge).
  CHANGELOG.md        -> the 2026-06-17/18 entries are PREPENDED (idempotent;
                         skipped if the v379 entry is already present).

Reversible: restore the .bak.premerge files.
"""
import base64
import gzip
import os

CL_PREPEND_B64 = ""
PRD_B64 = ""
ROADMAP_B64 = ""
DEDUP_ANCHOR = "v379 SMART_FILTER GRADE-GATE"


def _txt(b64):
    return gzip.decompress(base64.b64decode(b64)).decode("utf-8")


def _resolve(p):
    if os.path.exists(p):
        return p
    if os.path.exists(os.path.basename(p)):
        return os.path.basename(p)
    return p


def overwrite(path, b64):
    path = _resolve(path)
    new = _txt(b64)
    if os.path.exists(path):
        old = open(path, encoding="utf-8").read()
        if old == new:
            print(f"  {path}: already current, skipped")
            return
        open(path + ".bak.premerge", "w", encoding="utf-8").write(old)
    open(path, "w", encoding="utf-8").write(new)
    print(f"  {path}: overwritten ({len(new.splitlines())} lines; backup .bak.premerge)")


def prepend_changelog(path, b64, anchor):
    path = _resolve(path)
    block = _txt(b64)
    existing = open(path, encoding="utf-8").read() if os.path.exists(path) else ""
    if anchor and anchor in existing:
        print(f"  {path}: anchor present ('{anchor}') -> already caught up, skipped")
        return
    if existing:
        open(path + ".bak.premerge", "w", encoding="utf-8").write(existing)
    open(path, "w", encoding="utf-8").write(block + existing)
    print(f"  {path}: prepended {len(block.splitlines())} lines "
          f"(backup .bak.premerge)")


print("Catching memory/ tracking up to v379 ...")
overwrite("memory/PRD.md", PRD_B64)
overwrite("memory/ROADMAP.md", ROADMAP_B64)
prepend_changelog("memory/CHANGELOG.md", CL_PREPEND_B64, DEDUP_ANCHOR)
print("\nDone. Review:  git diff --stat memory/")
print("Then commit:  git add memory/ && git commit -m 'docs: catch memory tracking up to v379' && git push")
